#include <iostream>
#include <cmath>
#include <iomanip>

class Point {
private:
    int x_;
    int y_;

public:
    Point(int x, int y) : x_(x), y_(y) {}

    double getDistanceToOrigin() {
        return std::sqrt(static_cast<double>(x_ * x_) + static_cast<double>(y_ * y_));
    }
};

int main() {
    std::cout << std::fixed << std::setprecision(10);
    int x, y;
    while (std::cin >> x >> y) {
        Point p(x, y);
        std::cout << p.getDistanceToOrigin() << std::endl;
    }
    return 0;
}
